import React, { useEffect, useState } from "react";
import { createClient } from "@supabase/supabase-js";
import "./App.css";

const supabaseUrl = "https://cnakyamdydqxistdavfg.supabase.co";
const supabaseKey = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImNuYWt5YW1keWRxeGlzdGRhdmZnIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NTM5NDIzNTEsImV4cCI6MjA2OTUxODM1MX0.mAVSru38H63peSy0iH6nDdJ0WBxBwQcoVJwYMy9UKBo";
const supabase = createClient(supabaseUrl, supabaseKey);

const columnOrder = [
    "PROJE ADI",
    "TALEP",
    "TEDARİK",
    "VERİLEMEYEN",
    "TED. %",
    "SPOT",
    "FİLO",
    "TESİSTE",
    "GELECEK",
    "YÜKLENDİ",
    "HEDEF ÜSTÜ SEFER",
    "HEDEF ALTI SEFER",
    "HEDEF SEFER",
    "HEDEFSİZ SEFER",
    "ODAK_TALEP",
    "ODAK_TEDARİK",
    "ODAK_VERİLEMEYEN",
];

function App() {
    const [data, setData] = useState([]);
    const [odakData, setOdakData] = useState([]);

    useEffect(() => {
        async function fetchSupabaseData() {
            const { data, error } = await supabase
                .from("toplu_sonuclar")
                .select("json_data")
                .order("created_at", { ascending: false })
                .limit(1)
                .single();

            if (error) {
                console.error("Supabase veri çekme hatası:", error);
                return;
            }

            if (data && data.json_data) {
                setData(data.json_data);
            }
        }

        fetchSupabaseData();
    }, []);

    useEffect(() => {
        async function fetchOdakData() {
            const today = new Date().toISOString().split("T")[0];
            const payload = {
                startDate: `${today}T00:00:00`,
                endDate: `${today}T23:59:59`,
                userId: 1,
            };

            try {
                const response = await fetch("/api/tmsorders/getall", {
                    method: "POST",
                    headers: {
                        "Content-Type": "application/json",
                        Authorization:
                            "Bearer 49223653afa4b7e22c3659762c835dcdef9725a401e928fd46f697be8ea2597273bf4479cf9d0f7e5b8b03907c2a0b4d58625692c3e30629ac01fc477774de75",
                    },
                    body: JSON.stringify(payload),
                });

                const result = await response.json();
                const items = Array.isArray(result.Data) ? result.Data : [];

                const validItems = items
                    .filter(
                        (item) =>
                            item.MatchedSupabaseName && // eşleşme adı varsa
                            item.ProjectName &&
                            item.TMSVehicleRequestDocumentNo &&
                            item.OrderStatu !== 200
                    )
                    .reduce((acc, item) => {
                        const key = item.MatchedSupabaseName.trim().toUpperCase();

                        if (!acc[key]) {
                            acc[key] = {
                                MatchedSupabaseName: key,
                                Talep: 0,
                                Tedarik: 0,
                                Verilemeyen: 0,
                                _seen: new Set(),
                            };
                        }

                        const seenKey = item.TMSVehicleRequestDocumentNo;
                        if (!acc[key]._seen.has(seenKey)) {
                            acc[key]._seen.add(seenKey);
                            acc[key].Talep += 1;
                            item.TMSDespatchDocumentNo
                                ? acc[key].Tedarik++
                                : acc[key].Verilemeyen++;
                        }

                        return acc;
                    }, {});

                const resultArray = Object.values(validItems).map((p) => {
                    delete p._seen;
                    return p;
                });

                setOdakData(resultArray);
            } catch (err) {
                console.error("Odak API hatası:", err);
            }
        }

        fetchOdakData();
    }, []);

    // Supabase satırlarına doğrudan eşleşen Odak verisini entegre et
    useEffect(() => {
        if (data.length === 0 || odakData.length === 0) return;

        const header = data[0];
        const rows = data.slice(1);

        const merged = rows.map((row) => {
            const projeAdi = row["PROJE ADI"]?.trim().toUpperCase();

            const odak = odakData.find(
                (o) => o.MatchedSupabaseName === projeAdi
            );

            return {
                ...row,
                ODAK_TALEP: odak ? odak.Talep : 0,
                ODAK_TEDARİK: odak ? odak.Tedarik : 0,
                ODAK_VERİLEMEYEN: odak ? odak.Verilemeyen : 0,
            };
        });

        setData([header, ...merged]);
    }, [odakData]);

    return (
        <div className="app-container">
            <div className="section">
                <h2>🟢 Supabase + Odak Verileri (Net Eşleşme)</h2>
                {data.length > 0 ? (
                    <div className="table-wrapper">
                        <table className="styled-table">
                            <thead>
                                <tr>
                                    {columnOrder.map((col) => (
                                        <th key={col}>{col}</th>
                                    ))}
                                </tr>
                            </thead>
                            <tbody>
                                {data.slice(1).map((row, idx) => (
                                    <tr key={idx}>
                                        {columnOrder.map((col, i) => {
                                            let val = row[col];
                                            let style = {};

                                            if (col === "TED. %") {
                                                const parsed = parseFloat(val);
                                                if (!isNaN(parsed)) {
                                                    const percent = Math.round(parsed * 100);
                                                    val = `%${percent}`;
                                                    style = {
                                                        color:
                                                            percent < 70
                                                                ? "#e74c3c"
                                                                : percent < 90
                                                                    ? "#f39c12"
                                                                    : "#27ae60",
                                                        fontWeight: "bold",
                                                    };
                                                }
                                            }

                                            return (
                                                <td key={i} style={style}>
                                                    {typeof val === "number"
                                                        ? val.toLocaleString("tr-TR")
                                                        : val}
                                                </td>
                                            );
                                        })}
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                ) : (
                    <p className="loading">Veriler yükleniyor...</p>
                )}
            </div>
        </div>
    );
}

export default App;
